ds\"\r\n                            @printData=\"printData\"\r\n                            :records.sync=\"documents\"\r\n                            :pagination.sync=\"pagination.documents\"\r\n                            :type=\"'documents'\"\r\n                        >\r\n                        </document-print-detail>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane label=\"Cotizaciones\" name=\"quotations\">\r\n                        <document-print-detail\r\n                            :sender=\"sender\"\r\n                            :company=\"company\"\r\n                            @getRecords=\"getRecords\"\r\n                            @printData=\"printData\"\r\n                            :records.sync=\"quotations\"\r\n                            :pagination.sync=\"pagination.quotations\"\r\n                            :type=\"'quotations'\"\r\n                        >\r\n                        </document-print-detail>\r\n                    </el-tab-pane>\r\n                </el-tabs>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n<style>\r\n.el-dialog__header {\r\n    background-color: var(--primary) !important;\r\n}\r\n.el-dialog__title {\r\n    color: var(--light-text) !important;\r\n}\r\n.el-dialog__headerbtn .el-dialog__close {\r\n    color: white !important;\r\n}\r\n</style>\r\n<script>\r\nimport DocumentPrintDetail from \"./document_print_detail.vue\";\r\nimport queryString from \"query-string\";\r\nexport default {\r\n    components: { DocumentPrintDetail },\r\n    props: [\"showDialog\", \"company\", \"sender\", \"config\", \"establishment\"],\r\n    data() {\r\n        return {\r\n            time: null,\r\n            loading: false,\r\n            value: null,\r\n            typeSearch: \"document\",\r\n            saleNotes: [],\r\n            documents: [],\r\n            quotations: [],\r\n            pagination: {\r\n                saleNotes: {},\r\n                docume